  ('judicial-4d3895b1-moex-00024', 'judicial-4d3895b1', 'judicial-4d3895b1-moex-113-ab0300fb', 'sub-judicial-4d3895b1-01', NULL, 'essay', '甲向乙借款取得新臺幣（下同）300 萬元，除簽寫300 萬元借據給乙外，
並約定以甲妻丙所有之 A地設定本金最高限額 500 萬元之抵押權給乙。
屆期甲未還錢，乙乃檢附借據及相關資料，以丙為相對人聲請法院拍賣
抵押物求償 300萬元，法院裁定准許乙之聲請。試附理由回答下列問題：
甲在家收受法院送達其妻丙之准許拍賣抵押物裁定，甲認為法院裁定
所載之債權數額有誤，甲單獨以甲個人之名義對該裁定提起抗告，是
否適法？（10 分）
丙收受法院准許拍賣抵押物之裁定後，經甲告知已經償還乙300萬元，
並提出銀行匯款單為證，丙乃提出甲之銀行匯款單主張原裁定有誤，
應駁回乙之聲請而提起抗告。抗告法院認丙所提出甲之匯款單確屬真
正，則抗告法院應否撤銷原裁定，另為裁定？（15 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:27+00:00", "source_pdf_sha1": "a0d966788e2e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "101", "s": "0414", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公證法與非訟事件法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公證人"}'::jsonb, NULL)
